commands_run:
node <<'EOF'
const { readFileSync } = require('node:fs');
const source = readFileSync('./src/features/resources/hooks/useResources.ts', 'utf8');
console.log(JSON.stringify({
  hasEffectInResourceType: source.includes("| 'effect'"),
  hasEffectMetadataInterface: source.includes('export interface EffectMetadata'),
  hasEffectInMetadataUnion: source.includes('StructureVideoMetadata | EffectMetadata'),
  hasEffectInGuard: source.includes("type === 'effect'")
}, null, 2));
EOF

node --import tsx/esm <<'EOF'
import { buildGenerateEffectMessages, extractEffectCode } from './supabase/functions/ai-generate-effect/templates.ts';
const creation = buildGenerateEffectMessages({ prompt: 'Make the clip slide in from the left', category: 'entrance' });
const edit = buildGenerateEffectMessages({ prompt: 'Make it softer and slower', category: 'exit', existingCode: 'function Existing(){ return React.createElement(React.Fragment, null); }\nexports.default = Existing;' });
const extracted = extractEffectCode('```ts\nfunction Example(){ return React.createElement(AbsoluteFill, null); }\nexports.default = Example;\n```');
console.log(JSON.stringify({
  systemHasCreateElement: creation.systemMsg.includes('React.createElement'),
  systemHasExportsDefault: creation.systemMsg.includes('exports.default = ComponentName'),
  entranceGuidance: creation.userMsg.includes('opening effectFrames'),
  editIncludesExistingCode: edit.userMsg.includes('Existing code to modify'),
  editIncludesCodeSnippet: edit.userMsg.includes('function Existing()'),
  extractedStartsWithFunction: extracted.startsWith('function Example')
}, null, 2));
EOF
